# -*- coding: utf-8 -*-\n\nimport json\nfrom dataclasses import dataclass\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Optional, Tuple\n\n\n@dataclass(frozen=True)\nclass JiraSnapshotMeta:\n    run_id: str\n    generated_at: str\n    jql: str\n    project_key: str\n    analysis_depth_days: int\n\n\nclass JiraSnapshotStore:\n    def __init__(self, project_root: Path):\n        self.project_root = project_root\n        self.snapshots_dir = self.project_root / \"data\" / \"jira\" / \"snapshots\"\n        self.snapshots_dir.mkdir(parents=True, exist_ok=True)\n\n    def snapshot_path(self, run_id: str) -> Path:\n        return self.snapshots_dir / f\"{run_id}.json\"\n\n    def save_snapshot(\n        self,\n        run_id: str,\n        tasks: List[Dict[str, Any]],\n        *,\n        jql: str,\n        project_key: str,\n        analysis_depth_days: int,\n    ) -> Path:\n        meta = JiraSnapshotMeta(\n            run_id=run_id,\n            generated_at=datetime.now().isoformat(),\n            jql=jql,\n            project_key=project_key,\n            analysis_depth_days=analysis_depth_days,\n        )\n        payload = {\n            \"meta\": meta.__dict__,\n            \"tasks\": tasks,\n        }\n\n        path = self.snapshot_path(run_id)\n        path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding=\"utf-8\")\n        return path\n\n    def list_snapshots(self) -> List[Tuple[str, Path]]:\n        items: List[Tuple[str, Path]] = []\n        for p in sorted(self.snapshots_dir.glob(\"*.json\")):\n            items.append((p.stem, p))\n        return items\n\n    def find_previous_snapshot_path(self, run_id: str) -> Optional[Path]:\n        \"\"\"Находит снапшот с run_id строго меньше текущего (по имени run_id).\"\"\"\n        snapshots = [rid for rid, _ in self.list_snapshots()]\n        prev = [rid for rid in snapshots if rid < run_id]\n        if not prev:\n            return None\n        return self.snapshot_path(sorted(prev)[-1])\n\n    def load_snapshot(self, path: Path) -> Dict[str, Any]:\n        return json.loads(path.read_text(encoding=\"utf-8\"))\n
